import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const s = {
  page: { padding: 32, maxWidth: 560, margin: '0 auto' },
  card: { background: '#fff', borderRadius: 16, padding: '36px', boxShadow: '0 4px 20px rgba(0,0,0,0.08)' },
  title: { fontSize: 22, fontWeight: 700, color: '#1a3a5c', marginBottom: 24 },
  label: { display: 'block', fontSize: 13, fontWeight: 600, color: '#444', marginBottom: 6 },
  input: { width: '100%', padding: '11px 14px', border: '1.5px solid #ddd', borderRadius: 8, fontSize: 15, outline: 'none', marginBottom: 18 },
  select: { width: '100%', padding: '11px 14px', border: '1.5px solid #ddd', borderRadius: 8, fontSize: 15, outline: 'none', marginBottom: 18, background: '#fff' },
  btn: { width: '100%', padding: '13px', background: '#1a3a5c', color: '#fff', border: 'none', borderRadius: 8, fontSize: 16, fontWeight: 700, cursor: 'pointer' },
  err: { background: '#fdecea', color: '#c0392b', padding: 12, borderRadius: 8, marginBottom: 16, fontSize: 14 },
  success: { background: '#eafaf1', color: '#27ae60', padding: 12, borderRadius: 8, marginBottom: 16, fontSize: 14, fontWeight: 600 },
};

export default function ApplyPass() {
  const [form, setForm] = useState({ from: '', to: '', passType: 'monthly' });
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const set = (k) => (e) => setForm({ ...form, [k]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault(); setError(''); setSuccess(''); setLoading(true);
    try {
      await axios.post('/api/pass/apply', form);
      setSuccess('✅ Bus pass application submitted! Awaiting admin approval.');
      setTimeout(() => navigate('/my-passes'), 2000);
    } catch (err) {
      setError(err.response?.data?.message || 'Application failed');
    }
    setLoading(false);
  };

  return (
    <div style={s.page}>
      <div style={s.card}>
        <div style={s.title}>🎫 Apply for Bus Pass</div>
        {error && <div style={s.err}>{error}</div>}
        {success && <div style={s.success}>{success}</div>}
        <form onSubmit={handleSubmit}>
          <label style={s.label}>From (Boarding Point)</label>
          <input style={s.input} value={form.from} onChange={set('from')} required placeholder="e.g. Kuvempunagar" />
          <label style={s.label}>To (Destination)</label>
          <input style={s.input} value={form.to} onChange={set('to')} required placeholder="e.g. NIE College" />
          <label style={s.label}>Pass Type</label>
          <select style={s.select} value={form.passType} onChange={set('passType')}>
            <option value="monthly">Monthly</option>
            <option value="quarterly">Quarterly (3 months)</option>
            <option value="yearly">Yearly</option>
          </select>
          <button style={s.btn} disabled={loading}>{loading ? 'Submitting...' : 'Submit Application'}</button>
        </form>
      </div>
    </div>
  );
}
